import { type ReactNode } from 'react';
import type { AnnotationsMarkerConfig } from './annotations-marker-props.js';
/**
 * The annotations track slot props
 * @public
 */
export interface AnnotationsTrackProps {
    /**
     * Defines the marker background for all the markers inside a track, supporting any valid CSS color.
     * It will be overridden by any particular marker that has color prop defined.
     */
    color?: string;
    /**
     * The track label
     */
    label?: string;
    /**
     * Defines the marker symbol for all the markers inside a track, which can be a letter, an emoji, an icon or a Unicode character
     * It will be overridden by any particular marker that has symbol prop defined.
     */
    symbol?: ReactNode;
    /**
     * Specify whether a track should hide.
     * @defaultValue false
     */
    hidden?: boolean;
}
/** @internal */
export type AnnotationsTrackConfig = AnnotationsTrackProps & {
    /** Make hidden required internally */
    hidden: boolean;
    markers: AnnotationsMarkerConfig[];
};
